class Solution:
    def maxDistance(self, arrays):
        # Independent: gather (min, max, index) and pair best ends from different arrays.
        mins = [(a[0], i) for i, a in enumerate(arrays)]
        maxs = [(a[-1], i) for i, a in enumerate(arrays)]
        mins.sort()
        maxs.sort()
        best = 0
        # try the two smallest mins against the two largest maxs to dodge same-index clash
        for lo, li in mins[:2]:
            for hi, hj in reversed(maxs[-2:]):
                if li != hj:
                    best = max(best, hi - lo)
        return best

