class Solution:
    def maxDistance(self, arrays):
        cur_min = arrays[0][0]
        cur_max = arrays[0][-1]
        best = 0
        for a in arrays[1:]:
            best = max(best, a[-1] - cur_min, cur_max - a[0])
            cur_min = min(cur_min, a[0])
            cur_max = max(cur_max, a[-1])
        return best

